// ---------------------------------------------------------------------------
// Verify Request  —  שכבת אימות לוובהוק הציבורי.
//
// ללא הנוד הזה כל אדם באינטרנט יכול לשלוח JSON שרירותי, לגרום למערכת למשוך
// כל ריפו שהוא, לשרוף טוקנים של ה-LLM ואף לדחוף Commit עם ה-OAuth token שלנו.
//
// שני מסלולי אימות:
//   1. בקשה שמגיעה מ-GitHub  -> אימות חתימת HMAC-SHA256 (x-hub-signature-256)
//      מול הסוד המשותף שהוגדר ב-Webhook Secret של הריפו.
//   2. בקשה ידנית מדף התצוגה -> אין חתימה, ולכן מותרים רק מאגרים שנמצאים
//      ברשימת ההיתר (allow-list) של הפרויקט.
//
// הנוד אינו זורק שגיאה אלא מסמן verdict. הסיבה: זריקת שגיאה מחזירה לקורא
// תשובה ריקה וחסרת משמעות. במקום זה הענף הבא מחזיר 403 עם נימוק ברור.
// ---------------------------------------------------------------------------
const crypto = require('crypto');

// רשימת המאגרים שמותר לסרוק ללא חתימת GitHub (owner/repo, אותיות קטנות).
const ALLOWED_REPOS = [
  'levi2599/cyber-management-project'
];

// הסוד המשותף. מוגדר כמשתנה סביבה על שרת ה-n8n:
//   export GITHUB_WEBHOOK_SECRET='...'
const SECRET = $env.GITHUB_WEBHOOK_SECRET || '';

const item = items[0].json;
const headers = item.headers || {};
const body = item.body || {};

function reject(reason) {
  return [{ json: { ...item, verified: false, reject_reason: reason } }];
}

const fullName = (body.repository && body.repository.full_name) || '';
if (!fullName || fullName.split('/').length !== 2) {
  return reject('missing or malformed repository.full_name');
}

const signature = headers['x-hub-signature-256'] || headers['X-Hub-Signature-256'] || '';

if (signature) {
  // --- מסלול 1: בקשה חתומה מ-GitHub ---
  if (!SECRET) {
    return reject('signed request received but GITHUB_WEBHOOK_SECRET is not configured on the n8n server');
  }
  const expected = 'sha256=' + crypto
    .createHmac('sha256', SECRET)
    .update(JSON.stringify(body), 'utf8')
    .digest('hex');

  const a = Buffer.from(expected, 'utf8');
  const b = Buffer.from(String(signature), 'utf8');
  // timingSafeEqual דורש אורך זהה — בדיקת אורך מוקדמת מונעת חריגה.
  const valid = a.length === b.length && crypto.timingSafeEqual(a, b);
  if (!valid) {
    return reject('invalid x-hub-signature-256 (HMAC mismatch)');
  }
} else {
  // --- מסלול 2: הפעלה ידנית מדף התצוגה ---
  if (!ALLOWED_REPOS.includes(fullName.toLowerCase())) {
    return reject('unsigned request for a repository that is not in the allow-list (' + fullName + ')');
  }
}

return [{ json: { ...item, verified: true, reject_reason: '' } }];

// ---------------------------------------------------------------------------
// Parse Diff — עיבוד מקדים של קובץ ה-Diff.
// מטרה: להעביר ל-LLM רק את השורות שנוספו, במקום את ה-Diff הגולמי כולו.
// זה מקטין את כמות הטוקנים ואת עלות ה-inference.
// ---------------------------------------------------------------------------
const raw = items[0].json.data ?? items[0].json.body ?? items[0].json;
const diffText = typeof raw === 'string' ? raw : JSON.stringify(raw);

const hook = $('GitHub Webhook').item.json.body;

// נתיב הקובץ הראשון שהשתנה ב-Diff.
const pathMatch = diffText.match(/^\+\+\+ b\/(.+)$/m);
const filePath = pathMatch ? pathMatch[1].trim() : '';

// שורות שנוספו בלבד (מתעלמים מכותרות ה-Diff עצמן).
const addedLines = diffText
  .split('\n')
  .filter((l) => l.startsWith('+') && !l.startsWith('+++'))
  .map((l) => l.slice(1));

const addedCode = addedLines.join('\n').trim();

return [{
  json: {
    // אם לא זוהו שורות שנוספו — נשלח את הטקסט המלא כגיבוי.
    code_to_analyze: addedCode || diffText,
    source: 'github',
    repo_owner: hook.repository.owner.login,
    repo_name: hook.repository.name,
    pr_number: hook.number,
    branch: (hook.pull_request && hook.pull_request.head && hook.pull_request.head.ref) || 'main',
    file_path: filePath,
    diff_added_lines: addedLines.length,
    diff_total_chars: diffText.length
  }
}];

// ---------------------------------------------------------------------------
// Build Report — שכבת ה-Formatting (שלב 4 בדרישות המטלה).
//
// אחראית על שלושה דברים:
//   1. חילוץ מחרוזת וקטור ה-CVSS מתוך דוח הצוות האדום.
//   2. חילוץ *הקוד בלבד* מתוך פלט הצוות הכחול. זה קריטי: פלט הסוכן מורכב
//      מפרוזה בעברית + בלוק קוד. דחיפת הפלט הגולמי לריפו הייתה הורסת את
//      קובץ המקור.
//   3. הרכבת דוח Markdown קריא לפרסום ב-PR, בצ'אט וב-Google Drive.
// ---------------------------------------------------------------------------
const base = $('Normalize Input').item.json;
const redOutput = String($('Red Team Agent').item.json.output || '');
const blueOutput = String($('Blue Team Agent').item.json.output || '');

// --- 1. וקטור CVSS ---
const cvssMatch = redOutput.match(/CVSS:3\.1\/(?:[A-Z]{1,2}:[A-Z]\/?)+/);
const cvssVector = cvssMatch ? cvssMatch[0].replace(/\/$/, '') : '';

// --- 2. חילוץ בלוק הקוד מפלט הצוות הכחול ---
const noVuln = /NO_VULNERABILITIES_FOUND/i.test(redOutput);
const noFix = /NO_FIX_REQUIRED/i.test(blueOutput);

let fixedCode = '';
const blocks = [...blueOutput.matchAll(/```[a-zA-Z0-9_+-]*\n([\s\S]*?)```/g)].map((m) => m[1]);
if (blocks.length > 0) {
  // הבלוק הארוך ביותר הוא כמעט תמיד הקוד המתוקן המלא.
  fixedCode = blocks.sort((a, b) => b.length - a.length)[0].trim();
}

// דוחפים Commit רק אם באמת יש חולשה, יש קוד מתוקן, ויש נתיב קובץ אמיתי.
const hasFixedCode = Boolean(
  fixedCode &&
  fixedCode.length > 20 &&
  !noVuln &&
  !noFix &&
  base.file_path
);

// --- 3. דוח Markdown ---
const header = noVuln
  ? '## ✅ מבקר הקוד הכפול — לא נמצאו חולשות'
  : '## 🛡️ מבקר הקוד הכפול — דוח ביקורת אבטחה';

const reportParts = [
  header,
  '',
  '| שדה | ערך |',
  '| --- | --- |',
  '| מקור הבדיקה | ' + (base.source === 'github' ? 'GitHub Pull Request' : 'הזנת קוד ידנית') + ' |',
  '| קובץ | ' + (base.file_path || '—') + ' |',
  '| וקטור CVSS 3.1 | ' + (cvssVector || '— (לא דווחה חולשה)') + ' |',
  '| תיקון אוטומטי נדחף | ' + (hasFixedCode ? 'כן' : 'לא') + ' |',
  '',
  '### 🔴 ממצאי הצוות האדום (Red Team)',
  '',
  redOutput,
  '',
  '---',
  '',
  '### 🔵 תיקון הצוות הכחול (Blue Team)',
  '',
  blueOutput,
  '',
  '---',
  '',
  '_נוצר אוטומטית על ידי Dual Code Auditor · ' + new Date().toISOString() + '_'
];

return [{
  json: {
    ...base,
    cvss_vector_string: cvssVector,
    vulnerability_report: redOutput,
    blue_team_output: blueOutput,
    fixed_code: fixedCode,
    has_fixed_code: hasFixedCode,
    no_vulnerabilities_found: noVuln,
    full_report: reportParts.join('\n'),
    log_file_name: 'DualCodeAuditor_' + new Date().toISOString().replace(/[:.]/g, '-') + '.md'
  }
}];
